import sys
input = sys.stdin.readline

def solve(n, m):
    if n > m:
        return 0
    # find highest bit of m (since n<=m, m>=0)
    if m == 0:
        # n==0, n⊕0=0<=0=m, n⊕1=1>0=m, answer=1
        return 1
    b = m.bit_length() - 1
    nb = (n >> b) & 1
    mb = (m >> b) & 1
    mask = (1 << b) - 1
    if nb == 0 and mb == 0:
        return min(solve(n & mask, m & mask), 1 << b)
    elif nb == 1 and mb == 1:
        return solve(n & mask, m & mask)
    else:  # nb==0, mb==1
        return solve(n & mask, m & mask) | (1 << b)

t = int(input())
for _ in range(t):
    n, m = map(int, input().split())
    print(solve(n, m))

